head.script:
	scwin.today = "";
	scwin.rowIndex;

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSZZ1700000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 로그인한 사용자 ID 변수설정
		scwin.usrId = comLib.getUsrId();
		scwin.isAdmin = comLib.getAthrId() || "";
		var allowPGUsers = ['20160206','60002424','60002357']; // 수도운영
		var allowEGUsers = ['19922453','60002350']; //발전
		var allowWDUsers = ['19900921','20060842','60004007']; // 댐보운영

		if ($.inArray(comLib.getUsrEmpno(), allowWDUsers) !== -1) {
			dmaInqireParam.set("intnBiznDivCd", "WD");
		}else if($.inArray(comLib.getUsrEmpno(), allowEGUsers) !== -1) {
			dmaInqireParam.set("intnBiznDivCd", "EG");
		}else if($.inArray(comLib.getUsrEmpno(), allowPGUsers) !== -1) {
			dmaInqireParam.set("intnBiznDivCd", "PG");
		}
		// 공통코드 설정
		var options = [{clsCd : "SCM_0244", filter : ""}];

 		comLib.setCommonCodeSync($p, options, "");

		// 권한정보 조회
		dmaInqireParam.set("intnSysDivCd", comLib.getSysDivCd());
		scwin.setAthr();

		// 작업일자 설정한다.
		scwin.today = utilLib.getDate();

		dmaInqireParam.set("strtDt", utilLib.addToDay(utilLib.getCurrentDate("yyyyMMdd"), -1));
		dmaInqireParam.set("endDt", utilLib.getCurrentDate());
		dmaInqireParam.set("usrId", "");
		dmaInqireParam.set("usrNm", "");
		dmaInqireParam.set("prgstsCd", "RO");

		btnInqireUsr.setDisabled(false);
	};

	/**
 	 * 권한조회
	 * @param
	 * @return
	 */
	scwin.setAthr = function () {
		// 전체 권한그룹을 조회한다.(권한명이 지정되어 있을 경우 해당 권한만 조회)
		var requestData = {};
		requestData.dmaInqireParam = {"intnSysDivCd" : comLib.getSysDivCd()};

		var option = {
			action : "zz/authmng/retrieveAthrGrp.do",
			reqData : requestData,
			resData : dltAthrList,
			success : "scwin.setAthrSysDivCd",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
	 * @param
	 * @return
	 */
	scwin.setAthrSysDivCd = function () {
		var requestData = {};
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd":"SCM_0000"};

		var option = {
			action : "sc/authmng/retrieveAthrSysDivCd.do",
			reqData : requestData,
			resData : dltSysDivCdList,
			success : "scwin.retrieveAthrSysDivCdCallback",
			isShowMeg : false
		};
		ajaxLib.requestAjaxSyncCode($p, option);
	};

	/**
	 * 조회 CallBack 실행
	 * @param <Object> resBody
	 * @return
	 */
	scwin.retrieveAthrSysDivCdCallback = function (resBody, e) {
		if (dltSysDivCdList.getRowCount() == 0) {
			// 시스템관리자만 접근이 가능합니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
			return;
		}

		dmaInqireParam.set("intnSysDivCd", comLib.getSysDivCd());

		// 화면 오픈시 자동조회를 한다.
		comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire_onclick);
		scwin.btnInqire_onclick();
	};

	/**
	* 조회조건에 맞는 데이터 조회를 한다.
	* @param
	* @return
	*/
	scwin.btnInqire_onclick = function() {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();

		var option = {
			action : "zz/authmng/retrieveUsrAthrRqstAdmin.do",
			reqData : requestData,
			resData : dltUsrAthrRqstList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireCallback = function (resBody, e) {
		txtCnt.setValue("0");

		if (resBody.message.code == "success") {
			txtCnt.setValue(dltUsrAthrRqstList.getRowCount());
			for (var idx = 0; idx < dltUsrAthrRqstList.getRowCount(); idx++) {
				if (dltUsrAthrRqstList.getCellData(idx, "prgstsCd") == "CA") {
					grdUsrAthrRqst.setCellReadOnly(idx, "chk", true);
				}
			}
		} else {
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 사용자 조회
	* @param
	* @return
	 */
	scwin.btnInqireUsr_onclick = function() {
		var url = comLib.HRM_POP_URL + "/ui/hrm/cm/HRMCM10000006.xml";

		// 팝업창 옵션
		var option = {
			popupID : "HRMCM10000006",
			width : 700,
			height : 600,
			title : "사원 검색"
		};

		var strEnc = comLib.dataDecEnc(utilLib.getDate(), "E"); // 암호화 키값
		var usrInfo; // 세션정보 및 윈도우 타이틀
		usrInfo = JSON.stringify(comLib.getUserInfo4Param(strEnc, encodeURI(option.title)));

		var jsonObj = {
			// 필수값
			userInfo : usrInfo,
			closeCallbackFncName : "scwin.inqireUsrCallback",
			popupId : option.popupID,
			// 선택
			MULTI : "",
			AUTOI : ""
		};

		comLib.openPostWinPopup($p, url, option, jsonObj);
	};

	/**
	* 사용자 검색 CallBack 실행
	* @param <Object> retirnValue
	* @param <String> popupId
	* @return
	*/
	scwin.inqireUsrCallback = function(returnValue, popupId) {
		var selectedOrg = returnValue;

		dmaInqireParam.set("usrId", selectedOrg.PERNR);
		dmaInqireParam.set("usrNm", selectedOrg.ENAME);

		// 사용자 지정을 하고 바로 조회를 시행한다.
		scwin.btnInqire_onclick();
	};

	/**
	 * 신청목록에서 선택한 신청을 승인한다.
	 * @param
	 * @return
	 */
	scwin.btnAprv_onclick = function() {
		// 신규신청만 승인되어야 한다.
		for (var idx = 0; idx < dltUsrAthrRqstList.getRowCount(); idx++) {
			var usrAthrRqst = dltUsrAthrRqstList.getRowJSON(idx);

			if (usrAthrRqst.chk == "1" && usrAthrRqst.prgstsCd != "RO") {
				dltUsrAthrRqstList.setCellData(idx, "chk", "0");
				dltUsrAthrRqstList.modifyRowStatus(idx, "R");
			}
		}

		if (dltUsrAthrRqstList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		scwin.saveFlag = "U";
		scwin.saveCnfirm();
	};

	/**
	 * 신청목록에서 선택한 신청을 반려한다.
	 * @param
	 * @return
	 */
	scwin.btnRetn_onclick = function() {
		// 신청승인만 반려되어야 한다.
		for (var idx = 0; idx < dltUsrAthrRqstList.getRowCount(); idx++) {
			var usrAthrRqst = dltUsrAthrRqstList.getRowJSON(idx);

			if (usrAthrRqst.chk == "1" && usrAthrRqst.prgstsCd != "RA") {
				dltUsrAthrRqstList.setCellData(idx, "chk", "0");
				dltUsrAthrRqstList.modifyRowStatus(idx, "R");
			}
		}

		if (dltUsrAthrRqstList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		scwin.saveFlag = "D";
		scwin.saveCnfirm();
	};

	/**
	 * 저장, 삭제 여부를 물어본다.
	 * @param
	 * @return
	 */
	scwin.saveCnfirm = function() {
		if (scwin.saveFlag != "D") {
			// 승인할것인지 confirm
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00073", "신청내역"), "saveInfo");
		}
		else {
			// 반려할것인지 confirm
			comLib.confirm($p, utilLib.getMessage("SCM.INFO.00191", "신청"), "saveInfo");
		}
	};

	/**
	* 사용자별 권한그룹의 정보를 등록/수정/삭제한다.
	* @param
	* @return
	*/
	scwin.saveInfo = function() {
		var requestData = {};
		requestData.dltUsrAthrRqstList = dltUsrAthrRqstList.getModifiedJSON();

		var option = {
			action : "zz/authmng/saveUsrAthrRqst.do",
			reqData : requestData,
			success : "scwin.saveInfoCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 수정/저장 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveInfoCallback = function(resBody, e) {
		var prgstsCd;

		if (scwin.saveFlag == "D") {
			prgstsCd = "41";
			// 반려되었습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00331"));
		} else {
			prgstsCd = "40";
			// 승인되었습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00330"));
		}

		var usrAthrRqstList = dltUsrAthrRqstList.getModifiedJSON();
		var unifAthrRqstList = new Array();

		// 통합신청 건이면 통합신청목록에 추가한다.
		for (var idx = 0; idx < usrAthrRqstList.length; idx++) {
			if (usrAthrRqstList[idx].unifRqstSeq != null && usrAthrRqstList[idx].unifRqstSeq != "") {
				var unifAthrRqst = {
					rqstSeq : usrAthrRqstList[idx].unifRqstSeq,
					usrId : usrAthrRqstList[idx].usrId,
					usrNm : usrAthrRqstList[idx].usrNm,
					sysDivCd : usrAthrRqstList[idx].intnSysDivCd,
					athrId : usrAthrRqstList[idx].athrId,
					athrNm : dltAthrList.getMatchedJSON("athrId", usrAthrRqstList[idx].athrId)[0].athrNm,
					prgstsCd : prgstsCd
				};
				unifAthrRqstList.push(unifAthrRqst);
			}
		}

		// 통합신청목록이 있으면 통합신청상태를 업데이트 한다.
		if (unifAthrRqstList.length > 0) {
			var requestData = {};
			requestData.dltUnifAthrRqstDtlList = unifAthrRqstList;

			var option = {
				action : "/zz/authmng/transferUnifAthrRqst.do",
				reqData : requestData,
				isShowMeg : false
			};
			ajaxLib.executeAjax($p, option);
		}

		scwin.btnInqire_onclick();
	};

	/**
	 * 그리드에서 선택항목 체크시 승인자정보, 승인일 자동 기재
	 * @param
	 * @return
	 */
	scwin.grdUsrAthrRqst_onviewchange = function(info) {
		var rowIndex = info.rowIndex;
		var colIndex = info.colIndex;
		var oldValue = info.oldValue;
		var newValue = info.newValue;

		//선택 컬럼에 체크시 승인자정보, 승인일 자동 기재
		if (colIndex == 0) {
			if (newValue == "1") {
				var prgstsCd = dltUsrAthrRqstList.getCellData(rowIndex, "prgstsCd");

				var matchIndex = dltAthrList.getMatchedIndex("athrId", dltUsrAthrRqstList.getCellData(rowIndex, "athrId"));
				var intnSysDivCd = dltAthrList.getCellData(matchIndex, "intnSysDivCd");

				// 진행상태가 신청승인일 경우
				if (prgstsCd == "RA") {
					dltUsrAthrRqstList.setCellData(rowIndex, "canclDt", scwin.today);
					dltUsrAthrRqstList.setCellData(rowIndex, "intnSysDivCd", intnSysDivCd);
				} else if (prgstsCd == "RO") {
					// 진행상태가 신청일 경우
					dltUsrAthrRqstList.setCellData(rowIndex, "apprvrId", comLib.getUsrId());
					dltUsrAthrRqstList.setCellData(rowIndex, "apprvrNm", comLib.getUsrNm());
					dltUsrAthrRqstList.setCellData(rowIndex, "aprvDt", scwin.today);
					dltUsrAthrRqstList.setCellData(rowIndex, "canclDt", "");

					dltUsrAthrRqstList.setCellData(rowIndex, "intnSysDivCd", intnSysDivCd);
				} else if (prgstsCd == "CA") {
					comLib.alert($p, utilLib.getMessage("SCM.INFO.00056","이미 반려된 권한은 반려"));

					dltUsrAthrRqstList.setCellData(rowIndex, "chk", "0");
					dltUsrAthrRqstList.modifyRowStatus(rowIndex, "R");
				}
			} else {
				dltUsrAthrRqstList.modifyRowStatus(rowIndex, "R");
			}
		} else if(colIndex == '5') {
			dmaIngireUsrAthrUse.set("usrId", dltUsrAthrRqstList.getCellData(rowIndex, "usrId"));
			dmaIngireUsrAthrUse.set("athrId", newValue);

			scwin.inqireUsrAthrUse();
		}
	};

	/**
	 * 그리드헤더에서 선택항목 체크시 승인자정보, 승인일 자동 기재
	 * @param
	 * @return
	 */
	scwin.grdUsrAthrRqst_onheaderclick = function(headerId) {
		if (headerId == "chkHeader") {
			for (var idx = 0; idx < dltUsrAthrRqstList.getRowCount(); idx++) {
				var chkYn = dltUsrAthrRqstList.getCellData(idx, "chk");
				var prgstsCd = dltUsrAthrRqstList.getCellData(idx, "prgstsCd");

				// 체크여부가 true이면...
				if (chkYn == "1") {
					// 관리자 승인인 경우가 아닐때
					if (prgstsCd == "RO") {
						dltUsrAthrRqstList.setCellData(idx, "apprvrId", comLib.getUsrId());
						dltUsrAthrRqstList.setCellData(idx, "apprvrNm", comLib.getUsrNm());
						dltUsrAthrRqstList.setCellData(idx, "aprvDt", scwin.today);
						dltUsrAthrRqstList.setCellData(idx, "canclDt", "");
					} else if (prgstsCd == "RA") {
						dltUsrAthrRqstList.setCellData(idx, "canclDt", scwin.today);
					} else if (prgstsCd == "CA") {
						dltUsrAthrRqstList.setCellData(idx, "chk", "0");
						dltUsrAthrRqstList.modifyRowStatus(idx, "R");
					}
				} else {
					dltUsrAthrRqstList.modifyRowStatus(idx, "R");
				}
			}
		}
	};

	/**
	 * 초기화 하고 다시 조회를 한다.
	 * @param
	 * @return
	 */
	scwin.btnClear_onclick = function() {
		dmaInqireParam.reset();

		scwin.btnInqire_onclick();
	};

	/**
	 * 권한그룹 신청 시 권한그룹 선택을 할때 이미 등록이 된 건인지 확인을 한다.
	 * @param
	 * @return
	 */
	scwin.inqireUsrAthrUse = function () {
		var requestData = {};
		requestData.dmaIngireUsrAthrUse = dmaIngireUsrAthrUse.getModifiedJSON();

		var option = {
			action : "zz/authmng/selectUsrAthrUse.do",
			reqData : requestData,
			success : "scwin.inqireUsrAthrUseCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	* 사용자의 권한그룹이 이미 등록된 건이면 선택을 못하도록 한다.
	* @param <Object> resBody
	* @return
	*/
	scwin.inqireUsrAthrUseCallback = function(resBody, e) {
		var athrId = resBody.data.athrId;

		if(athrId != "") {
			// SCM.INFO.00275 이미 등록된 {0}입니다. 등록할 수 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00275", "권한ID"));

			var rowIndex = grdUsrAthrRqst.getFocusedRowIndex();
			dltUsrAthrRqstList.setCellData(rowIndex, "athrId", "");
		}
	};
